import { useEffect, useState } from 'react';
import { Alert, AlertDescription } from '@/components/ui/alert';

interface LeaveBalance {
  leaveType: string;
  available: number;
  used: number;
  pending: number;
}

export default function LeaveBalance() {
  const [balances, setBalances] = useState<LeaveBalance[]>([]);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    const mockBalances: LeaveBalance[] = [
      { leaveType: 'Vacation', available: 8, used: 4, pending: 1 },
      { leaveType: 'Sick Leave', available: 5, used: 1, pending: 0 },
      { leaveType: 'Personal', available: 3, used: 0, pending: 0 },
      { leaveType: 'Casual', available: 2, used: 1, pending: 0 },
    ];
    
    setBalances(mockBalances);
    setLoading(false);
  }, []);

  if (loading) return <div className="p-6">Loading...</div>;

  const totalAvailable = balances.reduce((sum, b) => sum + b.available, 0);
  const totalUsed = balances.reduce((sum, b) => sum + b.used, 0);
  const totalPending = balances.reduce((sum, b) => sum + b.pending, 0);

  return (
    <div className="p-6 space-y-6">
      <div>
        <h1 className="text-3xl font-bold">Leave Balance</h1>
        <p className="text-gray-600 mt-2">Leave balance for {new Date().getFullYear()}</p>
      </div>

      <div className="grid gap-4 md:grid-cols-4">
        <div className="p-4 bg-blue-50 border border-blue-200 rounded-lg">
          <p className="text-sm text-blue-600 font-medium">Total Available</p>
          <p className="text-3xl font-bold text-blue-900 mt-2">{totalAvailable}</p>
        </div>
        <div className="p-4 bg-green-50 border border-green-200 rounded-lg">
          <p className="text-sm text-green-600 font-medium">Used</p>
          <p className="text-3xl font-bold text-green-900 mt-2">{totalUsed}</p>
        </div>
        <div className="p-4 bg-yellow-50 border border-yellow-200 rounded-lg">
          <p className="text-sm text-yellow-600 font-medium">Pending</p>
          <p className="text-3xl font-bold text-yellow-900 mt-2">{totalPending}</p>
        </div>
        <div className="p-4 bg-purple-50 border border-purple-200 rounded-lg">
          <p className="text-sm text-purple-600 font-medium">Remaining</p>
          <p className="text-3xl font-bold text-purple-900 mt-2">{totalAvailable - totalUsed}</p>
        </div>
      </div>

      <div className="overflow-x-auto">
        <table className="w-full">
          <thead>
            <tr className="border-b">
              <th className="text-left p-2">Leave Type</th>
              <th className="text-left p-2">Available</th>
              <th className="text-left p-2">Used</th>
              <th className="text-left p-2">Pending</th>
              <th className="text-left p-2">Remaining</th>
            </tr>
          </thead>
          <tbody>
            {balances.map(b => (
              <tr key={b.leaveType} className="border-b hover:bg-gray-50">
                <td className="p-2 font-medium">{b.leaveType}</td>
                <td className="p-2 text-blue-600 font-semibold">{b.available}</td>
                <td className="p-2 text-green-600 font-semibold">{b.used}</td>
                <td className="p-2 text-yellow-600 font-semibold">{b.pending}</td>
                <td className="p-2 text-purple-600 font-semibold">{b.available - b.used}</td>
              </tr>
            ))}
          </tbody>
        </table>
      </div>

      <Alert>
        <AlertDescription>
          Leave balance resets on January 1st every year. Contact HR for policy details.
        </AlertDescription>
      </Alert>
    </div>
  );
}
